import java.util.HashMap;
import java.util.Map;

public static long solve(long[] nums, long k) {
    long currentSum = 0;
    long maxDeleted = 0;
    Map<Long, Long> remainderMap = new HashMap<>();
    remainderMap.put(0L, 0L);

    for (long num : nums) {
        currentSum += num;
        long remainder = currentSum % k;

        Long val = remainderMap.get(remainder);
        if (val != null) {
            long candidate = currentSum + val;
            if (candidate > maxDeleted) {
                maxDeleted = candidate;
            }
        }

        long newValue = maxDeleted - currentSum;
        if (remainderMap.containsKey(remainder)) {
            if (newValue > remainderMap.get(remainder)) {
                remainderMap.put(remainder, newValue);
            }
        } else {
            remainderMap.put(remainder, newValue);
        }
    }

    return currentSum - maxDeleted;
}
